use std::error::Error;
use std::num::ParseIntError;

fn parse_pos_nonzero(s: &str) -> Result<u64, Box<dyn Error>> {
    let n = s.parse::<i64>()?;
    if n <= 0 {
        let err = "Value must be positive and non-zero".to_string();
        return Err(err.into());
    }
    Ok(n as u64)
}

fn main() {
    println!("{:?}", parse_pos_nonzero("42"));
    println!("{:?}", parse_pos_nonzero("abc"));
    println!("{:?}", parse_pos_nonzero("-5"));
    println!("{:?}", parse_pos_nonzero("0"));
}
